const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { Pool } = require('pg');

// Initialize a new PostgreSQL pool
const pool = new Pool({
  user: 'your_username',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

// Define the GraphQL schema
const typeDefs = `
  type Query {
    posts: [Post]
  }

  type Post {
    id: ID!
    title: String!
    author: Author
  }

  type Author {
    id: ID!
    name: String!
  }
`;

// Define the GraphQL resolvers
const resolvers = {
  Query: {
    posts: async () => {
      const results = await pool.query('SELECT * FROM posts');
      return results.rows;
    },
  },
  Post: {
    author: async (post) => {
      const results = await pool.query(`SELECT * FROM authors WHERE id = ${post.authorId}`);
      return results.rows[0];
    },
  },
};

// Create a new GraphQL server using Express and the schema
const app = express();
app.use('/graphql', graphqlHTTP({ schema: typeDefs, resolvers }));

// Start the server
const port = 4000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});